sql:
SELECT warehouse_id, SUM(quantity) AS total_products
FROM product_warehouse_mapping
GROUP BY warehouse_id;

SELECT product_id, warehouse_id, quantity 
FROM product_warehouse_mapping 
WHERE mapping_id = 1000;

external_knowledge:
- "treasures" metaphorically refers to the products;
- "vaults" metaphorically refers to the warehouses;
- "depth in the vaults" metaphorically refers to the quantity of the product stored;
- "decade’s accumulation" metaphorically refers to a quantity greater than 10.

sql:
SELECT COUNT(product_id)
FROM product_category_mapping
WHERE category_id = (SELECT category_id FROM product_categories WHERE category_name = 'CategoryName');
